output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?script ?scriptLabel(COUNT(DISTINCT ?language) AS ?usageCount) WHERE {
  ?language wdt:P31 wd:Q34770 ; wdt:P282 ?script .
  OPTIONAL {
    ?script rdfs:label ?scriptLabel .
    FILTER(LANG(?scriptLabel) = "en")
  }
}
GROUP BY ?script ?scriptLabel
HAVING(?usageCount > 1)
ORDER BY DESC(?usageCount)

args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?script ?scriptLabel (COUNT(?language) AS ?count)
WHERE {
  ?language wdt:P282 ?script.
  OPTIONAL {
    ?script rdfs:label ?scriptLabel.
    FILTER(LANG(?scriptLabel) = "en")
  }
}
GROUP BY ?script ?scriptLabel
HAVING (COUNT(?language) > 1)
ORDER BY DESC(?count)

